async function seedQuestions() {
  try {
    // Fan bo'yicha minimal savollar soni (DTM 2026 standarti × 3 bufer)
    const MIN_PER_SUBJECT = {
      uztil: 50, math: 50, tarix: 50,
      bio: 100, kimyo: 100, fizika: 100, ingliz: 100,
      inform: 100, iqtisod: 80, rus: 80, geo: 80, adab: 80,
    };

    const subjectCounts = await TestQuestion.aggregate([
      { $group: { _id: '$subject', count: { $sum: 1 } } }
    ]);
    const existingMap = {};
    subjectCounts.forEach(s => existingMap[s._id] = s.count);
    const totalCount = subjectCounts.reduce((s, x) => s + x.count, 0);

    if (totalCount === 0) {
      const result = await TestQuestion.insertMany(QUESTIONS, { ordered: false });
      logger.info(`✅ ${result.length} ta savol yuklandi`);
      return;
    }

    // Har bir fan uchun minimum sondan kam bo'lsa qo'shamiz
    const toInsert = [];
    const subjects = [...new Set(QUESTIONS.map(q => q.subject))];
    for (const subj of subjects) {
      const existing = existingMap[subj] || 0;
      const min = MIN_PER_SUBJECT[subj] || 50;
      if (existing < min) {
        const subjQ = QUESTIONS.filter(q => q.subject === subj);
        toInsert.push(...subjQ);
        logger.info(`📚 ${subj}: ${existing} ta bor → ${subjQ.length} ta qo'shiladi`);
      }
    }

    // Mavjud bo'lmagan fanlarga tegishli savollarni qo'shamiz
    const missingQ = QUESTIONS.filter(q => !existingMap[q.subject] && !toInsert.includes(q));
    if (missingQ.length > 0) {
      const result = await TestQuestion.insertMany(missingQ, { ordered: false });
      logger.info(`✅ ${result.length} ta yangi savol qo'shildi (${[...new Set(missingQ.map(q => q.subject))].join(', ')})`);
    } else {
      logger.info(`Savollar bazada bor: ${totalCount} ta. Hamma fanlar mavjud.`);
    }
  } catch (err) {
    logger.error('Seed xato:', err.message);
  }
}

module.exports = { seedQuestions, QUESTIONS };

// Standalone ishga tushirish: node src/utils/seedQuestions.js
if (require.main === module) {
  require('dotenv').config();
  const { connectDB } = require('./db');
  connectDB().then(async () => {
    await seedQuestions();
    process.exit(0);
  });
}
